# ============= PERFORMANCE: CACHE HEADERS MIDDLEWARE =============
class CacheHeadersMiddleware:
    """Add appropriate cache headers for different response types - Pure ASGI middleware"""

    # Cacheable GET endpoints (public data that changes infrequently)
    LONG_CACHE_PATHS = [
        "/api/store-settings",
        "/api/referral-program",
        "/api/skincare-dictionary",
        "/api/ingredients",
        "/api/site-content",
        "/api/public/",
    ]
    
    # Short cache for product data (changes more frequently)
    PRODUCT_CACHE_PATHS = [
        "/api/products",
        "/api/featured-products",
    ]

    # Short cache for semi-dynamic data
    SHORT_CACHE_PATHS = [
        "/api/exchange-rates",
        "/api/currency/rates",
    ]

    # Never cache these (user-specific or sensitive)
    NO_CACHE_PATHS = [
        "/api/auth",
        "/api/cart",
        "/api/checkout",
        "/api/admin",
        "/api/user",
        "/api/orders",
        "/api/payments",
        "/api/chat",
    ]
    
    # SECURITY: Protected paths - block all web access
    BLOCKED_PATHS = [
        "/memory/",
        "/app/memory/",
        "/.env",
        "/backend/.env",
        "/frontend/.env",
        "/AUDIT_REPORT",
        "/PRD.md",
        "/SECRETS_POLICY",
        "/secrets/",
    ]

    # Static assets - cache for 1 year with immutable (fonts, images, etc.)
    IMMUTABLE_EXTENSIONS = [
        ".woff", ".woff2", ".ttf", ".otf", ".eot",
        ".avif", ".webp", ".png", ".jpg", ".jpeg", ".svg", ".ico",
    ]
    
    # Static paths - cache for 1 year with immutable (never change after deployment)
    IMMUTABLE_PATHS = ["/static/", "/icons/"]

    def __init__(self, app):
        self.app = app
    
    async def __call__(self, scope, receive, send):
        if scope["type"] != "http":
            await self.app(scope, receive, send)
            return
        
        path = scope.get("path", "")
        method = scope.get("method", "GET")
        
        # SECURITY: Block access to protected paths
        if any(blocked in path for blocked in self.BLOCKED_PATHS):
            response = StarletteResponse(
                content='{"error": "Forbidden", "message": "Access to this resource is not allowed"}',
                status_code=403,
                media_type="application/json"
            )
            await response(scope, receive, send)
            return
        
        # Skip health check endpoints immediately - critical for Kubernetes probes
        if path in ["/health", "/ready", "/", "/api/health"]:
            await self.app(scope, receive, send)
            return
        
        # Determine cache header based on path
        cache_header = None
        
        if method == "GET":
            # Immutable cache for /static/ and /icons/ paths - 1 year
            if any(path.startswith(p) for p in self.IMMUTABLE_PATHS):
                cache_header = b"public, max-age=31536000, immutable"
            # Immutable cache for static assets by extension
            elif any(path.endswith(ext) for ext in self.IMMUTABLE_EXTENSIONS):
                cache_header = b"public, max-age=31536000, immutable"
            # Never cache sensitive paths
            elif any(path.startswith(p) for p in self.NO_CACHE_PATHS):
                cache_header = b"no-store, no-cache, must-revalidate, private"
            # Long cache for static-like API data
            elif any(path.startswith(p) for p in self.LONG_CACHE_PATHS):
                cache_header = b"public, max-age=300, stale-while-revalidate=3600"
            # Product data - short cache
            elif any(path.startswith(p) for p in self.PRODUCT_CACHE_PATHS):
                cache_header = b"public, max-age=30, must-revalidate"
            # Semi-dynamic data
            elif any(path.startswith(p) for p in self.SHORT_CACHE_PATHS):
                cache_header = b"public, max-age=60, stale-while-revalidate=300"
            # Health endpoint
            elif path in ["/api/health", "/health"]:
                cache_header = b"public, max-age=10"
            else:
                cache_header = b"private, max-age=30"
        else:
            cache_header = b"no-store"
        
        # Wrap send to inject cache header
        async def send_with_cache(message):
            if message["type"] == "http.response.start":
                headers = list(message.get("headers", []))
                # Check status code - don't cache errors
                status = message.get("status", 200)
                if status >= 400:
                    headers.append((b"cache-control", b"no-store"))
                else:
                    headers.append((b"cache-control", cache_header))
                message = {**message, "headers": headers}
            await send(message)
        
        await self.app(scope, receive, send_with_cache)


app.add_middleware(CacheHeadersMiddleware)

