async def daily_digest_scheduler():
    """Background task that sends daily review digest at 9 AM"""
    import datetime as dt

    while True:
        try:
            now = datetime.now(timezone.utc)
            # Calculate time until next 9 AM UTC (adjust for your timezone)
            target_hour = 14  # 9 AM EST = 14:00 UTC
            next_run = now.replace(hour=target_hour, minute=0, second=0, microsecond=0)
            if now.hour >= target_hour:
                next_run += timedelta(days=1)

            wait_seconds = (next_run - now).total_seconds()
            logging.info(f"Daily digest scheduled in {wait_seconds/3600:.1f} hours")

            await asyncio.sleep(wait_seconds)

            # Send the digest
            logging.info("Running daily review digest...")
            await send_daily_review_digest()

            # Wait a bit to avoid double-triggering
            await asyncio.sleep(60)
        except Exception as e:
            logging.error(f"Daily digest scheduler error: {e}")
            await asyncio.sleep(3600)  # Wait an hour on error


