async def auto_repair_scheduler():
    """
    Background task that runs autonomous self-repair every 10 minutes.
    Detects errors, applies known fixes automatically, and uses AI for unknown issues.
    Only contacts admin for high-risk fixes.
    """
    # Wait for initial startup
    await asyncio.sleep(60)
    
    while True:
        try:
            logging.info("[AUTO_REPAIR] Starting autonomous repair cycle...")
            
            from services.auto_repair import run_autonomous_repair
            result = await run_autonomous_repair()
            
            if result.get('status') == 'completed':
                auto_fixed = len(result.get('auto_fixed', []))
                ai_actions = len(result.get('ai_actions', []))
                healthy = result.get('system_healthy', True)
                
                if auto_fixed > 0 or ai_actions > 0:
                    logging.info(f"[AUTO_REPAIR] Cycle complete: {auto_fixed} auto-fixed, {ai_actions} AI actions, healthy: {healthy}")
                else:
                    logging.debug("[AUTO_REPAIR] Cycle complete: No issues found")
            
            # Run every 10 minutes
            await asyncio.sleep(600)
            
        except Exception as e:
            logging.error(f"[AUTO_REPAIR] Scheduler error: {e}")
            await asyncio.sleep(300)  # Wait 5 minutes on error



async def monthly_data_cleanup_scheduler():
    """
    Monthly data retention cleanup - runs 1st of each month at 2 AM EST.
    
    Deletes:
    - Chat sessions older than 90 days
    - AI audit logs older than 180 days
    - Auto-heal logs older than 30 days
    
    GDPR compliance requirement.
    """
    import pytz
    est = pytz.timezone('America/Toronto')
    
    # Wait 2 minutes before starting to let everything initialize
    await asyncio.sleep(120)
    
    logging.info("[SCHEDULER] Monthly data cleanup scheduler started (runs 1st of month at 2 AM EST)")
    
    while True:
        try:
            now = datetime.now(est)
            
            # Calculate next 1st of month at 2 AM EST
            if now.day == 1 and now.hour < 2:
                # Today is the 1st and it's before 2 AM - run today
                target = now.replace(hour=2, minute=0, second=0, microsecond=0)
            else:
                # Calculate next 1st of month
                if now.month == 12:
                    target = now.replace(year=now.year + 1, month=1, day=1, hour=2, minute=0, second=0, microsecond=0)
                else:
                    target = now.replace(month=now.month + 1, day=1, hour=2, minute=0, second=0, microsecond=0)
            
            wait_seconds = (target - now).total_seconds()
            logging.info(f"[SCHEDULER] Monthly cleanup scheduled in {wait_seconds/86400:.1f} days")
            
            await asyncio.sleep(wait_seconds)
            
            # Run the cleanup
            logging.info("[SCHEDULER] Running monthly data cleanup...")
            result = await run_monthly_data_cleanup()
            
            if result.get("success"):
                logging.info(f"[SCHEDULER] Monthly cleanup complete: {result.get('total_deleted', 0)} records deleted")
            else:
                logging.error(f"[SCHEDULER] Monthly cleanup failed: {result.get('error')}")
            
            # Wait a bit to avoid double-triggering
            await asyncio.sleep(60)
            
        except Exception as e:
            logging.error(f"[SCHEDULER] Monthly cleanup scheduler error: {e}")
            await asyncio.sleep(86400)  # Wait a day on error


