async def daily_stock_alert_scheduler():
    """Daily 8am EST - Alert on low stock products via WhatsApp"""
    import pytz
    est = pytz.timezone('America/Toronto')
    
    while True:
        try:
            now = datetime.now(est)
            # Calculate next 8am EST
            target = now.replace(hour=8, minute=0, second=0, microsecond=0)
            if now >= target:
                target += timedelta(days=1)
            
            wait_seconds = (target - now).total_seconds()
            logging.info(f"[CRON] Stock alert scheduled for {target}, waiting {wait_seconds/3600:.1f}h")
            await asyncio.sleep(wait_seconds)
            
            # Find low stock products
            low_stock = await db.products.find(
                {"stock": {"$lt": 20, "$gt": 0}},
                {"_id": 0, "name": 1, "stock": 1}
            ).to_list(50)
            
            out_of_stock = await db.products.find(
                {"stock": {"$lte": 0}},
                {"_id": 0, "name": 1}
            ).to_list(50)
            
            if low_stock or out_of_stock:
                msg = "📦 *Daily Stock Alert*\n\n"
                
                if out_of_stock:
                    msg += "🔴 *OUT OF STOCK:*\n"
                    for p in out_of_stock[:10]:
                        msg += f"  • {p['name']}\n"
                    msg += "\n"
                
                if low_stock:
                    msg += "🟡 *LOW STOCK (<20):*\n"
                    for p in low_stock[:10]:
                        msg += f"  • {p['name']}: {p['stock']} left\n"
                
                # Send via WhatsApp
                admin_phone = os.environ.get("ADMIN_WHATSAPP", "+14168869408")
                await send_whatsapp_message(admin_phone, msg)
                logging.info(f"[CRON] Stock alert sent: {len(low_stock)} low, {len(out_of_stock)} out")
            else:
                logging.info("[CRON] Stock alert: All products well-stocked")
                
        except Exception as e:
            logging.error(f"[CRON] Stock alert error: {e}")
            await asyncio.sleep(3600)


async def weekly_revenue_summary_scheduler():
    """Weekly Monday 9am EST - Revenue summary via WhatsApp"""
    import pytz
    est = pytz.timezone('America/Toronto')
    
    while True:
        try:
            now = datetime.now(est)
            # Calculate next Monday 9am EST
            days_until_monday = (7 - now.weekday()) % 7
            if days_until_monday == 0 and now.hour >= 9:
                days_until_monday = 7
            
            target = (now + timedelta(days=days_until_monday)).replace(
                hour=9, minute=0, second=0, microsecond=0
            )
            
            wait_seconds = (target - now).total_seconds()
            logging.info(f"[CRON] Revenue summary scheduled for {target}, waiting {wait_seconds/3600:.1f}h")
            await asyncio.sleep(wait_seconds)
            
            # Get orders from past 7 days
            week_ago = datetime.now(timezone.utc) - timedelta(days=7)
            orders = await db.orders.find({
                "created_at": {"$gte": week_ago.isoformat()},
                "status": {"$in": ["completed", "shipped", "delivered"]}
            }).to_list(1000)
            
            total_revenue = sum(o.get("total", 0) for o in orders)
            order_count = len(orders)
            
            # Find top product
            product_counts = {}
            for order in orders:
                for item in order.get("items", []):
                    pid = item.get("product_id", item.get("name", "Unknown"))
                    product_counts[pid] = product_counts.get(pid, 0) + item.get("quantity", 1)
            
            top_product = max(product_counts.items(), key=lambda x: x[1]) if product_counts else ("N/A", 0)
            
            msg = f"""📊 *Weekly Revenue Summary*
_Week ending {now.strftime('%B %d, %Y')}_

💰 *Total Revenue:* CAD ${total_revenue:,.2f}
📦 *Orders:* {order_count}
🏆 *Top Product:* {top_product[0]} ({top_product[1]} sold)

_Reroots Aesthetics Inc._"""
            
            admin_phone = os.environ.get("ADMIN_WHATSAPP", "+14168869408")
            await send_whatsapp_message(admin_phone, msg)
            logging.info(f"[CRON] Weekly revenue sent: ${total_revenue:.2f}, {order_count} orders")
            
        except Exception as e:
            logging.error(f"[CRON] Revenue summary error: {e}")
            await asyncio.sleep(3600)


async def cnf_reminder_scheduler():
    """Friday 10am EST - CNF filing reminder until both AURA-GEN products are filed"""
    import pytz
    est = pytz.timezone('America/Toronto')
    
    while True:
        try:
            now = datetime.now(est)
            # Calculate next Friday 10am EST
            days_until_friday = (4 - now.weekday()) % 7
            if days_until_friday == 0 and now.hour >= 10:
                days_until_friday = 7
            
            target = (now + timedelta(days=days_until_friday)).replace(
                hour=10, minute=0, second=0, microsecond=0
            )
            
            wait_seconds = (target - now).total_seconds()
            logging.info(f"[CRON] CNF reminder scheduled for {target}, waiting {wait_seconds/3600:.1f}h")
            await asyncio.sleep(wait_seconds)
            
            # Check CNF status for AURA-GEN products
            auragen_products = await db.products.find({
                "name": {"$regex": "ARC|ACRC|AURA-GEN", "$options": "i"}
            }, {"_id": 0, "name": 1, "cnf_filed": 1}).to_list(10)
            
            unfiled = [p for p in auragen_products if not p.get("cnf_filed", False)]
            
            if unfiled:
                msg = f"""⚠️ *Health Canada CNF Reminder*

The following AURA-GEN products do NOT have confirmed CNF filings:

"""
                for p in unfiled:
                    msg += f"❌ {p['name']}\n"
                
                msg += """
*DO NOT SELL* these products until CNFs are confirmed.

File at: https://canada.ca/cosmetic-notification
_Reroots Aesthetics Inc._"""
                
                admin_phone = os.environ.get("ADMIN_WHATSAPP", "+14168869408")
                await send_whatsapp_message(admin_phone, msg)
                logging.info(f"[CRON] CNF reminder sent: {len(unfiled)} products unfiled")
            else:
                logging.info("[CRON] CNF reminder: All AURA-GEN products filed ✓")
                # Stop the scheduler once all are filed
                break
                
        except Exception as e:
            logging.error(f"[CRON] CNF reminder error: {e}")
            await asyncio.sleep(3600)


# ============= SMS NOTIFICATION SYSTEM (TWILIO) =============


async def send_sms_verification(phone: str) -> dict:
    """Send SMS verification code using Twilio Verify"""
    if not twilio_client or not TWILIO_VERIFY_SERVICE_SID:
        logging.warning("Twilio not configured - SMS verification skipped")
        return {"success": False, "error": "SMS service not configured"}

    try:
        # Format phone number (ensure it has country code)
        if not phone.startswith("+"):
            phone = f"+1{phone}"  # Default to Canada/US

        verification = twilio_client.verify.v2.services(
            TWILIO_VERIFY_SERVICE_SID
        ).verifications.create(to=phone, channel="sms")

        logging.info(f"✓ SMS verification sent to {phone[:6]}***")
        return {"success": True, "status": verification.status, "sid": verification.sid}
    except Exception as e:
        logging.error(f"SMS verification failed: {e}")
        return {"success": False, "error": str(e)}


async def verify_sms_code(phone: str, code: str) -> dict:
    """Verify SMS code using Twilio Verify"""
    if not twilio_client or not TWILIO_VERIFY_SERVICE_SID:
        logging.warning("Twilio not configured - SMS verification skipped")
        return {"success": False, "error": "SMS service not configured"}

    try:
        # Format phone number
        if not phone.startswith("+"):
            phone = f"+1{phone}"

        verification_check = twilio_client.verify.v2.services(
            TWILIO_VERIFY_SERVICE_SID
        ).verification_checks.create(to=phone, code=code)

        if verification_check.status == "approved":
            logging.info(f"✓ SMS code verified for {phone[:6]}***")
            return {"success": True, "status": "approved"}
        else:
            return {
                "success": False,
                "status": verification_check.status,
                "error": "Invalid code",
            }
    except Exception as e:
        logging.error(f"SMS verification check failed: {e}")
        return {"success": False, "error": str(e)}


async def send_sms_notification(phone: str, message: str) -> dict:
    """Send a direct SMS notification using Twilio Messaging"""
    if not twilio_client:
        logging.warning("Twilio not configured - SMS notification skipped")
        return {"success": False, "error": "SMS service not configured", "mock": True}

    try:
        # Format phone number
        if not phone.startswith("+"):
            phone = f"+1{phone}"

        # Use Twilio Verify to send SMS (more reliable for notifications)
        # Alternatively, you can use twilio_client.messages.create() with a phone number
        verification = twilio_client.verify.v2.services(
            TWILIO_VERIFY_SERVICE_SID
        ).verifications.create(
            to=phone, channel="sms", custom_message=message[:160]  # SMS limit
        )

        logging.info(f"✓ SMS notification sent to {phone[:6]}***")
        return {"success": True, "status": verification.status}
    except Exception as e:
        logging.error(f"SMS notification failed: {e}")
        return {"success": False, "error": str(e)}


