# ============= PASSWORD RESET =============


class PasswordResetRequest(BaseModel):
    email: EmailStr


class PasswordResetConfirm(BaseModel):
    token: str
    new_password: str


def create_reset_token(email: str) -> str:
    """Create a password reset token valid for 1 hour"""
    payload = {
        "email": email,
        "type": "password_reset",
        "exp": datetime.now(timezone.utc).timestamp() + 3600,  # 1 hour
    }
    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)


def verify_reset_token(token: str) -> Optional[str]:
    """Verify password reset token and return email if valid"""
    try:
        payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
        if payload.get("type") != "password_reset":
            return None
        return payload.get("email")
    except Exception:
        return None


@api_router.post("/auth/forgot-password")
async def forgot_password(request_data: PasswordResetRequest, request: Request):
    """Request a password reset email"""
    email = request_data.email.lower().strip()

    # Check if user exists (check both users and team_members)
    user = await db.users.find_one({"email": email}, {"_id": 0})
    team_member = await db.team_members.find_one({"email": email}, {"_id": 0})

    if not user and not team_member:
        # Don't reveal if email exists or not for security
        return {
            "message": "If an account exists with this email, you will receive a password reset link.",
            "success": False,
        }

    # Generate reset token
    reset_token = create_reset_token(email)
    
    # Get user's name for personalized email
    name = "there"
    if user:
        name = user.get("name") or user.get("first_name") or "there"
    elif team_member:
        name = team_member.get("name") or team_member.get("first_name") or "there"

    # Get the frontend URL from request or use default - use /app for PWA
    origin = request.headers.get("origin", "")
    if not origin or origin == "null":
        origin = "https://reroots.ca"
    reset_link = f"{origin}/app?reset_token={reset_token}"

    email_sent = False

    # Try to send email if Resend is configured
    if RESEND_API_KEY:
        try:
            html_content = f"""
            <div style="background:#060608;color:#F0EBE0;padding:40px;font-family:Georgia,serif;">
                <h2 style="color:#C9A86E;margin-bottom:20px;">Password Reset</h2>
                <p style="margin-bottom:16px;">Hi {name},</p>
                <p style="margin-bottom:24px;">Click below to reset your password. Link expires in 1 hour.</p>
                <a href="{reset_link}" 
                   style="background:#C9A86E;color:#060608;padding:14px 28px;
                          text-decoration:none;border-radius:4px;display:inline-block;
                          font-family:sans-serif;letter-spacing:0.1em;font-size:12px;">
                    RESET PASSWORD
                </a>
                <p style="color:#5C5548;font-size:12px;margin-top:24px;">
                    If you didn't request this, ignore this email.
                </p>
                <hr style="border:none;border-top:1px solid #1a1a1a;margin:30px 0;"/>
                <p style="color:#3a3a3a;font-size:11px;">reroots.ca · Canadian Biotech Skincare</p>
            </div>
            """

            params = {
                "from": "ReRoots <hello@reroots.ca>",
                "to": [email],
                "subject": "Reset your ReRoots password",
                "html": html_content,
            }

            result = await asyncio.to_thread(resend.Emails.send, params)
            # Check if email was actually sent (Resend returns an ID on success)
            if result and hasattr(result, "id") and result.id:
                logging.info(f"Password reset email sent to: {email}, ID: {result.id}")
                email_sent = True
            else:
                logging.warning(
                    f"Resend returned no ID, email may not be delivered: {result}"
                )
                email_sent = False
        except Exception as e:
            error_msg = str(e)
            logging.error(f"Failed to send password reset email: {error_msg}")
            # Check for domain verification error
            if "not verified" in error_msg.lower() or "domain" in error_msg.lower():
                logging.warning(
                    "Domain not verified in Resend - returning link directly"
                )
            email_sent = False

    # ALWAYS return the reset link for now (until email domain is verified)
    # This ensures password reset works regardless of email service status
    logging.info(f"Returning reset link directly: {reset_link}")
    return {
        "message": "If this email exists, you will receive reset instructions.",
        "success": True,
        "reset_link": reset_link,
        "email_sent": email_sent,
    }


@api_router.post("/auth/reset-password")
async def reset_password(request_data: PasswordResetConfirm):
    """Reset password using the token from email"""
    email = verify_reset_token(request_data.token)

    if not email:
        raise HTTPException(status_code=400, detail="Invalid or expired reset token")

    # Validate new password
    is_valid, message = validate_password_strength(request_data.new_password)
    if not is_valid:
        raise HTTPException(status_code=400, detail=message)

    # Hash the new password
    hashed_password = hash_password(request_data.new_password)

    # Update user password
    user_result = await db.users.update_one(
        {"email": email}, {"$set": {"password": hashed_password}}
    )

    # Also update team member if exists
    team_result = await db.team_members.update_one(
        {"email": email}, {"$set": {"password_hash": hashed_password}}
    )

    if user_result.modified_count == 0 and team_result.modified_count == 0:
        raise HTTPException(status_code=404, detail="Account not found")

    logging.info(f"Password reset successful for: {email}")
    return {
        "message": "Password reset successful. You can now log in with your new password."
    }


@api_router.get("/auth/verify-reset-token")
async def verify_token(token: str):
    """Verify if a reset token is valid"""
    email = verify_reset_token(token)
    if not email:
        raise HTTPException(status_code=400, detail="Invalid or expired reset token")
    return {"valid": True, "email": email}


