@api_router.post("/auth/phone-login")
async def phone_login(data: dict):
    """Login or register with phone number using SMS verification"""
    phone = data.get("phone")
    code = data.get("code")

    if not phone:
        raise HTTPException(status_code=400, detail="Phone number required")

    # If no code provided, send verification
    if not code:
        result = await send_sms_verification(phone)
        if not result.get("success"):
            raise HTTPException(
                status_code=500, detail=result.get("error", "Failed to send SMS")
            )
        return {"message": "Verification code sent", "awaiting_code": True}

    # Verify the code
    verify_result = await verify_sms_code(phone, code)
    if not verify_result.get("success"):
        raise HTTPException(status_code=400, detail="Invalid verification code")

    # Format phone
    formatted_phone = phone if phone.startswith("+") else f"+1{phone}"

    # Find or create user
    user = await db.users.find_one({"phone": formatted_phone}, {"_id": 0})

    if not user:
        # Create new user with phone
        user = {
            "id": str(uuid.uuid4()),
            "email": None,
            "first_name": "User",
            "last_name": formatted_phone[-4:],  # Last 4 digits
            "phone": formatted_phone,
            "phone_verified": True,
            "role": "customer",
            "created_at": datetime.now(timezone.utc).isoformat(),
        }
        await db.users.insert_one(user)
        user.pop("_id", None)
    else:
        # Update phone verification status
        await db.users.update_one(
            {"id": user["id"]}, {"$set": {"phone_verified": True}}
        )

    # Generate token
    token_payload = {
        "user_id": user["id"],
        "email": user.get("email"),
        "phone": formatted_phone,
        "role": user.get("role", "customer"),
        "exp": datetime.now(timezone.utc) + timedelta(days=7),
    }
    token = jwt.encode(token_payload, JWT_SECRET, algorithm=JWT_ALGORITHM)

    return {
        "token": token,
        "user": {
            "id": user["id"],
            "email": user.get("email"),
            "first_name": user.get("first_name"),
            "last_name": user.get("last_name"),
            "phone": formatted_phone,
            "role": user.get("role", "customer"),
        },
    }


@api_router.post("/auth/password-reset-sms")
async def password_reset_via_sms(data: dict):
    """Reset password using SMS verification"""
    phone = data.get("phone")
    code = data.get("code")
    new_password = data.get("new_password")

    if not phone:
        raise HTTPException(status_code=400, detail="Phone number required")

    # If no code, send verification
    if not code:
        # Check if user exists with this phone
        formatted_phone = phone if phone.startswith("+") else f"+1{phone}"
        user = await db.users.find_one({"phone": formatted_phone})
        if not user:
            raise HTTPException(
                status_code=404, detail="No account found with this phone number"
            )

        result = await send_sms_verification(phone)
        if not result.get("success"):
            raise HTTPException(
                status_code=500, detail=result.get("error", "Failed to send SMS")
            )
        return {"message": "Verification code sent", "awaiting_code": True}

    # Verify code and reset password
    if not new_password:
        raise HTTPException(status_code=400, detail="New password required")

    verify_result = await verify_sms_code(phone, code)
    if not verify_result.get("success"):
        raise HTTPException(status_code=400, detail="Invalid verification code")

    # Update password
    formatted_phone = phone if phone.startswith("+") else f"+1{phone}"
    hashed = bcrypt.hashpw(new_password.encode("utf-8"), bcrypt.gensalt())

    result = await db.users.update_one(
        {"phone": formatted_phone}, {"$set": {"password_hash": hashed.decode("utf-8")}}
    )

    if result.modified_count == 0:
        raise HTTPException(status_code=404, detail="User not found")

    return {"message": "Password reset successful"}


