@api_router.get("/admin/clinical-logic/milestones")
async def get_milestone_templates(request: Request):
    """Get all milestone templates"""
    await require_admin(request)
    
    # Check if custom milestones exist in DB
    milestones = await db.milestone_templates.find().to_list(50)
    
    if not milestones:
        # Seed with defaults
        for m in DEFAULT_MILESTONE_TEMPLATES:
            m["created_at"] = datetime.now(timezone.utc).isoformat()
            await db.milestone_templates.insert_one(m.copy())
        milestones = await db.milestone_templates.find().to_list(50)
    
    for m in milestones:
        m["id"] = str(m.pop("_id", m.get("id", "")))
    
    return {"milestones": milestones, "forbidden_words": FORBIDDEN_COSMETIC_WORDS}


@api_router.post("/admin/clinical-logic/milestones")
async def create_milestone_template(data: dict, request: Request):
    """Create a new milestone template"""
    await require_admin(request)
    
    # Validate required fields
    if not data.get("phase_name") or not data.get("tags"):
        raise HTTPException(status_code=400, detail="Phase name and tags are required")
    
    # Check for forbidden words
    description = data.get("description", "").lower()
    found_forbidden = [w for w in FORBIDDEN_COSMETIC_WORDS if w in description]
    if found_forbidden:
        return {
            "success": False,
            "error": "Forbidden cosmetic words detected",
            "forbidden_words": found_forbidden,
            "suggestions": {w: COSMETIC_WORD_SUGGESTIONS.get(w, "approved alternative") for w in found_forbidden}
        }
    
    milestone = {
        "id": f"milestone-{uuid.uuid4().hex[:8]}",
        "tags": data.get("tags", []),
        "phase_name": data.get("phase_name"),
        "day_start": data.get("day_start", 1),
        "day_end": data.get("day_end", 14),
        "description": data.get("description", ""),
        "priority": data.get("priority", 5),
        "is_active": data.get("is_active", True),
        "created_at": datetime.now(timezone.utc).isoformat()
    }
    
    await db.milestone_templates.insert_one(milestone)
    milestone.pop("_id", None)
    
    logging.info(f"Milestone template created: {milestone['phase_name']}")
    return {"success": True, "milestone": milestone}


@api_router.put("/admin/clinical-logic/milestones/{milestone_id}")
async def update_milestone_template(milestone_id: str, data: dict, request: Request):
    """Update a milestone template"""
    await require_admin(request)
    
    # Check for forbidden words
    description = data.get("description", "").lower()
    found_forbidden = [w for w in FORBIDDEN_COSMETIC_WORDS if w in description]
    if found_forbidden:
        return {
            "success": False,
            "error": "Forbidden cosmetic words detected",
            "forbidden_words": found_forbidden,
            "suggestions": {w: COSMETIC_WORD_SUGGESTIONS.get(w, "approved alternative") for w in found_forbidden}
        }
    
    from bson import ObjectId
    try:
        filter_query = {"_id": ObjectId(milestone_id)}
    except:
        filter_query = {"id": milestone_id}
    
    update_data = {
        "tags": data.get("tags"),
        "phase_name": data.get("phase_name"),
        "day_start": data.get("day_start"),
        "day_end": data.get("day_end"),
        "description": data.get("description"),
        "priority": data.get("priority"),
        "is_active": data.get("is_active"),
        "updated_at": datetime.now(timezone.utc).isoformat()
    }
    # Remove None values
    update_data = {k: v for k, v in update_data.items() if v is not None}
    
    result = await db.milestone_templates.update_one(filter_query, {"$set": update_data})
    
    if result.matched_count == 0:
        raise HTTPException(status_code=404, detail="Milestone not found")
    
    logging.info(f"Milestone template updated: {milestone_id}")
    return {"success": True, "message": "Milestone updated"}


