@api_router.post("/admin/clinical-logic/generate-calendar")
async def generate_calendar_preview(data: dict, request: Request):
    """
    Generate a calendar preview based on product tags.
    This assembles the "Lego blocks" of milestones based on detected tags.
    """
    await require_admin(request)
    
    product_ids = data.get("product_ids", [])
    if not product_ids:
        raise HTTPException(status_code=400, detail="Product IDs required")
    
    # Fetch products and collect all tags
    all_tags = set()
    products_info = []
    total_active = 0.0
    has_sensitive = False
    
    for pid in product_ids:
        product = await db.products.find_one({"id": pid})
        if product:
            product_tags = product.get("tags", [])
            all_tags.update(product_tags)
            concentration = product.get("active_concentration", 0) or 0
            total_active += concentration
            
            if "SENSITIVE" in product_tags:
                has_sensitive = True
            
            products_info.append({
                "id": pid,
                "name": product.get("name", ""),
                "tags": product_tags,
                "concentration": concentration
            })
    
    # Determine label style based on SENSITIVE tag
    label_style = "sooth_protect" if has_sensitive else "engine_buffer"
    
    # Fetch milestone templates
    milestones = await db.milestone_templates.find({"is_active": True}).to_list(50)
    if not milestones:
        # Use defaults
        milestones = DEFAULT_MILESTONE_TEMPLATES
    
    # Filter milestones that match product tags
    matching_milestones = []
    for m in milestones:
        milestone_tags = m.get("tags", [])
        # Check if any product tag matches any milestone tag
        if any(tag in all_tags for tag in milestone_tags):
            matching_milestones.append({
                "id": str(m.get("_id", m.get("id", ""))),
                "phase_name": m.get("phase_name"),
                "day_start": m.get("day_start"),
                "day_end": m.get("day_end"),
                "description": m.get("description"),
                "priority": m.get("priority", 5),
                "matched_tags": [t for t in milestone_tags if t in all_tags]
            })
    
    # Sort by priority (lower = higher priority) then by day_start
    matching_milestones.sort(key=lambda x: (x["priority"], x["day_start"]))
    
    # Check for high potency warning
    potency_warning = None
    if total_active > 60:
        potency_warning = f"⚠️ High Potency Alert: {total_active:.2f}% total active concentration. Review Safety FAQ."
    
    # Generate pro-tip based on formulation
    pro_tip = None
    if total_active >= 40:
        pro_tip = f"🛡️ Pro-Tip: Your {total_active:.2f}% protocol is potent. If you're using the Accelerator (Step 1) for the first time, skip every other night for Week 1 to allow your surface barrier to adapt."
    
    return {
        "success": True,
        "products": products_info,
        "all_tags": list(all_tags),
        "total_active_percent": round(total_active, 2),
        "label_style": label_style,
        "milestones": matching_milestones,
        "potency_warning": potency_warning,
        "pro_tip": pro_tip
    }


@api_router.post("/admin/clinical-logic/validate-text")
async def validate_cosmetic_compliance(data: dict, request: Request):
    """Validate text for Canadian cosmetic compliance"""
    await require_admin(request)
    
    text = data.get("text", "").lower()
    
    found_forbidden = []
    suggestions = {}
    
    for word in FORBIDDEN_COSMETIC_WORDS:
        if word in text:
            found_forbidden.append(word)
            suggestions[word] = COSMETIC_WORD_SUGGESTIONS.get(word, "approved alternative")
    
    return {
        "is_compliant": len(found_forbidden) == 0,
        "forbidden_words": found_forbidden,
        "suggestions": suggestions
    }


