# AI Product Generator - Generate product details from formulation
@api_router.post("/admin/generate-product-details")
async def generate_product_details(data: dict, request: Request):
    """
    AI-powered product detail generator.
    Takes formulation/ingredients and generates all product details.
    """
    await require_admin(request)
    
    formulation = data.get("formulation", "").strip()
    if not formulation:
        raise HTTPException(status_code=400, detail="Formulation/ingredients are required")
    
    # Get optional context
    product_type = data.get("product_type", "skincare serum")
    brand_voice = data.get("brand_voice", "premium scientific skincare")
    
    try:
        from emergentintegrations.llm.chat import LlmChat, UserMessage
        
        llm_key = get_claude_api_key()
        if not llm_key:
            raise HTTPException(status_code=500, detail="AI service not configured")
        
        chat = LlmChat(
            api_key=llm_key,
            session_id=f"product_gen_{uuid.uuid4()}",
            system_message="""You are an expert skincare product copywriter for ReRoots, a premium biotech skincare brand.
Your task is to generate compelling, scientific yet accessible product details from ingredient formulations.

Brand Voice: Premium, scientific, results-driven, clean beauty focused.
Target Audience: Health-conscious consumers who value effective, science-backed skincare.

Always respond in valid JSON format only, no markdown or extra text."""
        ).with_model("anthropic", "claude-sonnet-4-5-20250929")
        
        prompt = f"""Generate complete product details for this {product_type} formulation:

FORMULATION/INGREDIENTS:
{formulation}

Generate a JSON object with these exact fields:
{{
    "name": "Product name (creative, memorable, include key active if notable)",
    "short_description": "One-line tagline (max 60 chars)",
    "description": "Full marketing description (2-3 paragraphs, benefits-focused)",
    "ingredients": "Full INCI ingredient list formatted properly",
    "key_benefits": ["benefit1", "benefit2", "benefit3", "benefit4"],
    "how_to_use": "Application instructions (step by step)",
    "target_concerns": ["concern1", "concern2", "concern3"],
    "skin_types": ["suitable skin type 1", "suitable skin type 2"],
    "texture": "Product texture description",
    "size_ml": 30,
    "suggested_price_usd": 0
}}

Be specific about percentages and actives. Make it sound premium but accessible.
Return ONLY the JSON object, no markdown formatting."""

        user_message = UserMessage(text=prompt)
        response = await chat.send_message(user_message)
        
        # Parse the JSON response
        import json
        # Clean response - remove markdown code blocks if present
        clean_response = response.strip()
        if clean_response.startswith("```"):
            clean_response = clean_response.split("```")[1]
            if clean_response.startswith("json"):
                clean_response = clean_response[4:]
        clean_response = clean_response.strip()
        
        try:
            product_details = json.loads(clean_response)
        except json.JSONDecodeError:
            # Try to extract JSON from response
            import re
            json_match = re.search(r'\{[\s\S]*\}', clean_response)
            if json_match:
                product_details = json.loads(json_match.group())
            else:
                raise HTTPException(status_code=500, detail="Failed to parse AI response")
        
        logging.info(f"AI generated product details for formulation: {formulation[:50]}...")
        return {
            "success": True,
            "generated": product_details
        }
        
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"AI product generation failed: {e}")
        raise HTTPException(status_code=500, detail=f"AI generation failed: {str(e)}")


