@api_router.put("/products/{product_id}")
async def update_product(product_id: str, product_data: dict, request: Request):
    """Update a single product with STRICT ID scoping to prevent data mismatch"""
    await require_admin(request)
    
    # P0 FIX: Ensure product_id is a valid unique string
    if not product_id or not isinstance(product_id, str):
        raise HTTPException(status_code=400, detail="Valid product_id required")
    
    # P0 FIX: Verify product exists BEFORE updating
    existing = await db.products.find_one({"id": product_id})
    if not existing:
        raise HTTPException(status_code=404, detail=f"Product {product_id} not found")
    
    # Capture previous stock for restock notification check
    prev_stock = existing.get("stock", 0) or existing.get("quantity", 0) or 0
    
    # P0 FIX: Remove any _id field from update data to prevent ObjectId conflicts
    update_data = {k: v for k, v in product_data.items() if k != "_id"}
    
    # P0 FIX: Add updated_at timestamp
    update_data["updated_at"] = datetime.now(timezone.utc).isoformat()
    
    # P0 FIX: Use EXPLICIT filter with unique product_id
    result = await db.products.update_one(
        {"id": product_id},  # STRICT ID scope - only updates THIS product
        {"$set": update_data}
    )
    
    if result.modified_count == 0 and result.matched_count == 0:
        logging.warning(f"Product update failed - no document matched: {product_id}")
        raise HTTPException(status_code=404, detail="Product not found or no changes made")
    
    # Fetch the updated product
    updated = await db.products.find_one({"id": product_id}, {"_id": 0})
    
    # WAITLIST RESTOCK: Trigger notifications if stock went from 0 → available
    new_stock = update_data.get("stock", 0) or update_data.get("quantity", 0) or 0
    if new_stock > 0 and prev_stock == 0:
        try:
            restock_result = await trigger_restock_notifications(db, product_id, new_stock, prev_stock)
            if restock_result.get("fired"):
                logging.info(f"🔔 Restock notifications triggered for {product_id}: {restock_result.get('notified', 0)} notified")
        except Exception as e:
            logging.warning(f"Restock notification error for {product_id}: {e}")
    
    # LOW STOCK ALERT: Send admin email if stock drops below reorder point
    reorder_point = updated.get("reorder_point", 10) if updated else 10
    if new_stock <= reorder_point and new_stock > 0:
        try:
            from routers.email_service import send_low_stock_alert
            send_low_stock_alert(
                product_name=updated.get("name", "Unknown Product"),
                sku=updated.get("sku", product_id),
                current_stock=new_stock,
                reorder_point=reorder_point
            )
        except Exception as e:
            logging.warning(f"Low stock alert email failed: {e}")
    
    # Invalidate product caches so changes reflect everywhere
    invalidate_cache()
    
    # Broadcast to all clients to refresh this product
    await ws_manager.broadcast_to_all({
        "type": "product_sync",
        "action": "updated",
        "product_id": product_id,
        "product_name": updated.get("name") if updated else None
    })
    
    logging.info(f"Product updated: {product_id} - {updated.get('name') if updated else 'Unknown'}")
    return updated


@api_router.delete("/products/{product_id}")
async def delete_product(product_id: str, request: Request):
    await require_admin(request)
    
    # Get product name before deleting
    product = await db.products.find_one({"id": product_id}, {"_id": 0})
    product_name = product.get("name") if product else None
    
    await db.products.delete_one({"id": product_id})
    
    # Invalidate product caches
    invalidate_cache()
    
    # Broadcast to all clients to remove this product
    await ws_manager.broadcast_to_all({
        "type": "product_sync",
        "action": "deleted",
        "product_id": product_id,
        "product_name": product_name
    })
    
    return {"message": "Product deleted"}


