@api_router.post("/ai/science-assistant")
async def science_formulation_assistant(data: dict, request: Request):
    """AI-powered skincare science and formulation assistant"""
    await require_admin(request)

    query = sanitize_input(data.get("query", ""))
    query_type = data.get("query_type", "ingredient")

    if not query:
        raise HTTPException(status_code=400, detail="Query is required")

    try:
        from emergentintegrations.llm.chat import LlmChat, UserMessage
        
        llm_key = get_claude_api_key()

        system_prompts = {
            "ingredient": """You are an expert cosmetic chemist and skincare formulation scientist. 
Analyze ingredients with scientific accuracy. Include:
- Chemical properties and mechanisms of action
- Clinical evidence and studies
- Optimal concentrations
- Skin penetration and bioavailability
- Potential side effects and contraindications
Reference scientific studies when possible.""",
            "formulation": """You are an expert cosmetic formulator specializing in skincare products.
Help with formulation questions including:
- Ingredient compatibility and interactions
- pH considerations and stability
- Emulsion systems and texture
- Preservation requirements
- Manufacturing considerations
Provide practical, science-based formulation advice.""",
            "comparison": """You are a skincare scientist comparing ingredients and products.
Provide balanced, evidence-based comparisons including:
- Efficacy differences backed by research
- Suitable skin types for each option
- Cost-effectiveness considerations
- Formulation stability differences
- Real-world results expectations""",
            "benefits": """You are a cosmetic claims specialist and regulatory expert.
Help with product benefits and claims by:
- Identifying substantiated claims based on ingredients
- Suggesting clinical study references
- Explaining mechanism of action for each claim
- Noting regulatory considerations (FDA, Health Canada)
- Differentiating between structure/function and drug claims""",
            "compatibility": """You are a skincare routine optimization expert.
Analyze ingredient and product compatibility:
- Identify potential interactions (positive and negative)
- Suggest optimal layering order
- Recommend timing (AM/PM usage)
- Note pH compatibility issues
- Suggest alternatives for incompatible combinations""",
            "concentration": """You are a cosmetic formulation expert specializing in active concentrations.
Provide detailed concentration guidance:
- Evidence-based optimal ranges
- Safety thresholds and irritation potential
- Efficacy vs tolerance trade-offs
- Build-up protocols for sensitive skin
- Clinical study concentrations for reference""",
        }

        system_message = system_prompts.get(query_type, system_prompts["ingredient"])
        system_message += """

Format your response clearly with sections and bullet points. Be thorough but concise.
Always note when something requires professional consultation (dermatologist, cosmetic chemist)."""

        chat = LlmChat(
            api_key=llm_key,
            session_id=f"science-assistant-{query_type}",
            system_message=system_message,
        ).with_model("anthropic", "claude-sonnet-4-5-20250929")

        user_message = UserMessage(text=query)
        response = await chat.send_message(user_message)

        return {"response": response.strip(), "query_type": query_type}
    except Exception as e:
        logging.error(f"Science AI error: {e}")
        raise HTTPException(status_code=500, detail="Failed to process science query")


@api_router.post("/ai/science-content")
async def generate_science_content(data: dict, request: Request):
    """Generate Health Canada compliant science content for marketing"""
    await require_admin(request)
    
    system_prompt = sanitize_input(data.get("systemPrompt", ""))
    user_prompt = sanitize_input(data.get("userPrompt", ""))
    max_tokens = data.get("maxTokens", 1000)
    
    if not user_prompt:
        raise HTTPException(status_code=400, detail="userPrompt is required")
    
    try:
        from emergentintegrations.llm.chat import LlmChat, UserMessage
        
        llm_key = get_claude_api_key()
        
        default_system = """You are a Health Canada compliant cosmetic science copywriter for ReRoots, a premium Canadian biotech skincare brand.
HEALTH CANADA COMPLIANCE RULES — MANDATORY:
- NEVER use: heal, cure, treat, acne, melasma, scar, dna repair, anti-inflammatory, diagnose, prevent disease
- ALWAYS qualify claims with: "visibly", "appearance of", "look of", "helps support", "may help"
- This is cosmetic copy, NOT drug/medical claims"""
        
        chat = LlmChat(
            api_key=llm_key,
            session_id=f"science-content-{datetime.utcnow().timestamp()}",
            system_message=system_prompt if system_prompt else default_system,
        ).with_model("anthropic", "claude-sonnet-4-5-20250929")
        
        user_message = UserMessage(text=user_prompt)
        response = await chat.send_message(user_message)
        
        return {"content": response.strip(), "text": response.strip(), "response": response.strip()}
    except Exception as e:
        logging.error(f"Science content generation error: {e}")
        raise HTTPException(status_code=500, detail=f"Failed to generate science content: {str(e)}")


@api_router.get("/admin/security-status")
async def get_security_status(request: Request):
    """Get security status and recent activity"""
    await require_admin(request)

    # Get site protection settings
    site_settings = await db.site_settings.find_one({"type": "security"}, {"_id": 0})
    if not site_settings:
        site_settings = {
            "type": "security",
            "password_protection": False,
            "bot_blocking": False,
            "maintenance_mode": False,
            "allowed_ips": [],
            "blocked_ips": []
        }
        await db.site_settings.insert_one(site_settings)

    # Get recent failed logins (anonymized)
    recent_lockouts = []
    current_time = time.time()
    for email, attempts in failed_logins.items():
        if len(attempts) >= 3:  # Show accounts with 3+ failed attempts
            recent_lockouts.append(
                {
                    "email_hash": hash(email) % 10000,  # Anonymized
                    "attempts": len(attempts),
                    "locked": len(attempts) >= LOCKOUT_THRESHOLD,
                    "last_attempt": (
                        datetime.fromtimestamp(max(attempts)).isoformat()
                        if attempts
                        else None
                    ),
                }
            )

    # Count total rate limited IPs from Redis-backed rate limiter
    try:
        rate_limiter_stats = await rate_limiter.get_stats()
        rate_limited_count = rate_limiter_stats.get("active_keys", 0)
    except:
        rate_limited_count = 0

    return {
        "site_protection": {
            "password_protection": site_settings.get("password_protection", False),
            "bot_blocking": site_settings.get("bot_blocking", False),
            "maintenance_mode": site_settings.get("maintenance_mode", False),
            "crawl_enabled": not site_settings.get("bot_blocking", False),  # Inverse for clarity
        },
        "security_features": {
            "rate_limiting": True,
            "brute_force_protection": True,
            "password_hashing": "bcrypt",
            "jwt_authentication": True,
            "input_sanitization": True,
            "security_headers": True,
            "xss_protection": True,
            "account_lockout": True,
        },
        "current_status": {
            "accounts_with_failed_logins": len(recent_lockouts),
            "locked_accounts": sum(1 for l in recent_lockouts if l["locked"]),
            "rate_limited_ips": rate_limited_count,
        },
        "recommendations": [
            "Use strong passwords (8+ chars, uppercase, lowercase, number)",
            "Enable 2FA when available",
            "Regularly review order activity",
            "Keep admin credentials secure",
        ],
    }


@api_router.get("/admin/security-settings")
async def get_security_settings(request: Request):
    """Get current site security settings"""
    await require_admin(request)
    
    settings = await db.site_settings.find_one({"type": "security"})
    
    if not settings:
        # Return defaults if no settings exist
        return {
            "password_protection": False,
            "bot_blocking": False,
            "maintenance_mode": False,
            "crawl_enabled": True,
            "updated_at": None
        }
    
    return {
        "password_protection": settings.get("password_protection", False),
        "bot_blocking": settings.get("bot_blocking", False),
        "maintenance_mode": settings.get("maintenance_mode", False),
        "crawl_enabled": not settings.get("bot_blocking", False),  # Inverse
        "updated_at": settings.get("updated_at")
    }


@api_router.post("/admin/security-settings")
async def update_security_settings(request: Request, data: dict = Body(...)):
    """Update site security settings (password protection, bot blocking, etc.)"""
    await require_admin(request)
    
    setting_type = data.get("setting")
    enabled = data.get("enabled", False)
    
    valid_settings = ["password_protection", "bot_blocking", "maintenance_mode", "crawl_enabled"]
    
    if setting_type not in valid_settings:
        raise HTTPException(status_code=400, detail=f"Invalid setting. Must be one of: {valid_settings}")
    
    # Handle crawl_enabled as inverse of bot_blocking
    if setting_type == "crawl_enabled":
        setting_type = "bot_blocking"
        enabled = not enabled
    
    # Update the setting
    await db.site_settings.update_one(
        {"type": "security"},
        {
            "$set": {
                setting_type: enabled,
                "updated_at": datetime.now(timezone.utc).isoformat()
            }
        },
        upsert=True
    )
    
    # Log the change
    await db.admin_audit_log.insert_one({
        "id": str(uuid.uuid4()),
        "action": "security_setting_changed",
        "setting": setting_type,
        "new_value": enabled,
        "timestamp": datetime.now(timezone.utc).isoformat()
    })
    
    return {
        "success": True,
        "setting": setting_type,
        "enabled": enabled,
        "message": f"{setting_type.replace('_', ' ').title()} {'enabled' if enabled else 'disabled'}"
    }


