@api_router.get("/admin/marketing-audience")
async def get_marketing_audience(request: Request):
    """Get target audience data from bio-scans for marketing asset generation"""
    await require_admin(request)

    # Get total bio-scans
    total = await db.bio_scans.count_documents({})

    # Get high-intent leads (those tagged with intent:high)
    high_intent = await db.bio_scans.count_documents(
        {"customer_tags": {"$in": ["intent:high"]}}
    )

    # Aggregate concerns from customer_tags
    concern_pipeline = [
        {"$unwind": "$customer_tags"},
        {"$match": {"customer_tags": {"$regex": "^concern:"}}},
        {
            "$group": {
                "_id": {
                    "$substr": ["$customer_tags", 8, -1]
                },  # Remove "concern:" prefix
                "count": {"$sum": 1},
            }
        },
        {"$sort": {"count": -1}},
        {"$limit": 10},
    ]
    concerns_result = await db.bio_scans.aggregate(concern_pipeline).to_list(10)
    concerns = {item["_id"]: item["count"] for item in concerns_result}

    # Get recent leads (last 10)
    recent_leads = (
        await db.bio_scans.find(
            {},
            {
                "_id": 0,
                "email": 1,
                "customer_tags": 1,
                "created_at": 1,
                "risk_level": 1,
            },
        )
        .sort("created_at", -1)
        .to_list(10)
    )

    # Mask emails for privacy
    for lead in recent_leads:
        if lead.get("email"):
            parts = lead["email"].split("@")
            if len(parts) == 2:
                lead["email"] = parts[0][:3] + "***@" + parts[1]

    return {
        "total": total,
        "high_intent": high_intent,
        "concerns": concerns,
        "recent_leads": recent_leads,
    }


