@api_router.post("/webhook/whapi")
async def whapi_webhook(request: Request, data: dict = Body(...)):
    """
    Whapi.cloud webhook endpoint for real-time message/event updates.
    Configure this URL in your Whapi.cloud dashboard:
    https://reroots.ca/api/webhook/whapi

    This enables:
    - Real-time referral verification updates
    - Instant dashboard refresh when referrals complete scans
    - Message delivery confirmations
    """
    try:
        event_type = data.get("event") or data.get("type")

        # Log webhook event
        await db.whapi_webhook_logs.insert_one(
            {
                "id": str(uuid.uuid4()),
                "event_type": event_type,
                "data": data,
                "received_at": datetime.now(timezone.utc).isoformat(),
            }
        )

        # Handle different event types
        if event_type == "message":
            # Incoming message from user
            message = data.get("message", {})
            from_number = message.get("from") or data.get("from")
            body = message.get("body", {}).get("text", "") or message.get("text", "")

            # Check if this is a reply to a milestone notification
            if from_number and body:
                # Auto-respond to common queries
                body_lower = body.lower()
                if any(
                    word in body_lower for word in ["help", "question", "how", "what"]
                ):
                    # Send helpful response
                    await send_whatsapp_message(
                        from_number,
                        "Thanks for reaching out! 🙂\n\nVisit reroots.ca for our full FAQ, or reply with your specific question and our team will get back to you.\n\n- ReRoots Lab",
                    )
                elif any(
                    word in body_lower
                    for word in ["thank", "thanks", "awesome", "great"]
                ):
                    await send_whatsapp_message(
                        from_number,
                        "You're welcome! 💜 Let us know if you need anything else.\n\n- ReRoots Lab",
                    )

        elif event_type == "message.status":
            # Message delivery status update
            status = data.get("status")
            message_id = data.get("message_id")
            if status == "delivered" or status == "read":
                logger.info(f"WhatsApp message {message_id} was {status}")

        elif event_type == "contact.joined":
            # New contact started chat - potential lead!
            contact = data.get("contact", {})
            phone = contact.get("phone") or contact.get("wa_id")
            name = contact.get("pushname") or contact.get("name", "")

            if phone:
                # Record as potential lead in Data Hub
                await db.whatsapp_leads.update_one(
                    {"phone": phone},
                    {
                        "$set": {
                            "phone": phone,
                            "name": name,
                            "source": "whatsapp_webhook",
                            "updated_at": datetime.now(timezone.utc).isoformat(),
                        },
                        "$setOnInsert": {
                            "id": str(uuid.uuid4()),
                            "created_at": datetime.now(timezone.utc).isoformat(),
                        },
                    },
                    upsert=True,
                )
                logger.info(f"New WhatsApp lead captured: {phone[:5]}***")

        return {"status": "ok", "received": True}

    except Exception as e:
        logger.error(f"Whapi webhook error: {str(e)}")
        # Always return 200 to prevent webhook retries
        return {"status": "ok", "error": str(e)}


