# ============ ADMIN PRICING CONTROLS ============


@api_router.get("/admin/founding-pricing")
async def get_founding_pricing():
    """Get Founding Member pricing configuration - SINGLE DISCOUNT, MAX 30%"""
    pricing = await db.admin_settings.find_one({"key": "founding_pricing"}, {"_id": 0})

    if not pricing or not pricing.get("value"):
        # Default pricing - CORRECTED: Single 30% discount, no stacking
        retail_value = 100.0
        referral_discount_percent = 30  # Default max discount
        final_price = retail_value * (1 - referral_discount_percent / 100)
        return {
            "retail_value": retail_value,
            "referral_discount_percent": referral_discount_percent,
            "max_discount_percent": 30,  # Hard cap
            "final_price": round(final_price, 2),
        }

    return pricing.get("value", {})


@api_router.get("/founding-member/pricing")
async def get_founding_member_pricing_public():
    """Public endpoint to get Founding Member pricing for the page"""
    pricing = await db.admin_settings.find_one({"key": "founding_pricing"}, {"_id": 0})

    if not pricing or not pricing.get("value"):
        # Default: $100 - 30% = $70
        return {
            "retail_value": 100.0,
            "referral_discount_percent": 30,
            "final_price": 70.0,
        }

    value = pricing.get("value", {})
    return {
        "retail_value": value.get("retail_value", 100.0),
        "referral_discount_percent": value.get("referral_discount_percent", 30),
        "final_price": value.get("final_price", 70.0),
    }


@api_router.put("/admin/founding-pricing")
async def update_founding_pricing(data: dict):
    """Update Founding Member pricing - SINGLE DISCOUNT, HARD CAP AT 30%"""
    retail_value = float(data.get("retail_value", 100))
    referral_discount = float(data.get("referral_discount_percent", 30))

    # HARD CAP: Maximum discount is 30% - prevents revenue loss
    MAX_DISCOUNT = 30
    if referral_discount > MAX_DISCOUNT:
        referral_discount = MAX_DISCOUNT
        logger.warning(f"Referral discount capped at {MAX_DISCOUNT}%")

    if referral_discount < 0:
        referral_discount = 0

    # Simple calculation: Retail - Single Discount = Final Price
    # NO STACKING - just one discount percentage
    final_price = retail_value * (1 - referral_discount / 100)

    pricing_config = {
        "retail_value": retail_value,
        "referral_discount_percent": referral_discount,
        "max_discount_percent": MAX_DISCOUNT,  # Always show the cap
        "final_price": round(final_price, 2),
        "updated_at": datetime.now(timezone.utc).isoformat(),
    }

    await db.admin_settings.update_one(
        {"key": "founding_pricing"},
        {"$set": {"key": "founding_pricing", "value": pricing_config}},
        upsert=True,
    )

    logger.info(
        f"Founding pricing updated: ${retail_value} - {referral_discount}% = ${pricing_config['final_price']}"
    )

    return {"success": True, "pricing": pricing_config}


