@api_router.get("/admin/paypal-links")
async def get_paypal_links(request: Request):
    """Get all PayPal price-based links"""
    await require_admin(request)
    links = await db.paypal_links.find({}, {"_id": 0}).sort("amount", 1).to_list(100)
    return links


@api_router.post("/admin/paypal-links")
async def create_paypal_link(link_data: PayPalLinkCreate, request: Request):
    """Create a new PayPal link for a specific price point"""
    await require_admin(request)
    
    link = PayPalLink(
        amount=link_data.amount,
        link_url=link_data.link_url,
        label=link_data.label,
        is_active=link_data.is_active
    )
    link_dict = link.model_dump()
    link_dict["created_at"] = link_dict["created_at"].isoformat()
    
    await db.paypal_links.insert_one(link_dict)
    
    return {"success": True, "link": {k: v for k, v in link_dict.items() if k != "_id"}}


@api_router.put("/admin/paypal-links/{link_id}")
async def update_paypal_link(link_id: str, link_data: dict, request: Request):
    """Update an existing PayPal link"""
    await require_admin(request)
    
    update_fields = {}
    if "amount" in link_data:
        update_fields["amount"] = float(link_data["amount"])
    if "link_url" in link_data:
        update_fields["link_url"] = link_data["link_url"]
    if "label" in link_data:
        update_fields["label"] = link_data["label"]
    if "is_active" in link_data:
        update_fields["is_active"] = link_data["is_active"]
    
    if update_fields:
        await db.paypal_links.update_one({"id": link_id}, {"$set": update_fields})
    
    updated = await db.paypal_links.find_one({"id": link_id}, {"_id": 0})
    return {"success": True, "link": updated}


@api_router.delete("/admin/paypal-links/{link_id}")
async def delete_paypal_link(link_id: str, request: Request):
    """Delete a PayPal link"""
    await require_admin(request)
    
    result = await db.paypal_links.delete_one({"id": link_id})
    return {"success": result.deleted_count > 0}


@api_router.get("/paypal-links/match/{amount}")
async def match_paypal_link(amount: float):
    """Find the best matching PayPal link for a given order amount.
    Returns the link with the closest amount that is >= order total.
    If no exact or higher match, returns the highest available link.
    """
    # Get all active links sorted by amount
    links = await db.paypal_links.find(
        {"is_active": True}, {"_id": 0}
    ).sort("amount", 1).to_list(100)
    
    if not links:
        return {"matched": False, "link": None, "message": "No PayPal links configured"}
    
    # Find the first link with amount >= order total (exact or higher)
    for link in links:
        if link["amount"] >= amount:
            return {
                "matched": True,
                "link": link,
                "match_type": "exact" if link["amount"] == amount else "higher",
                "difference": round(link["amount"] - amount, 2)
            }
    
    # If no link covers the amount, return the highest available
    highest_link = links[-1]
    return {
        "matched": True,
        "link": highest_link,
        "match_type": "highest_available",
        "difference": round(amount - highest_link["amount"], 2),
        "message": f"Order total ${amount} exceeds highest link ${highest_link['amount']}. Customer may need to pay difference."
    }


@api_router.get("/public/paypal-links")
async def get_public_paypal_links():
    """Public endpoint to get active PayPal links for checkout"""
    links = await db.paypal_links.find(
        {"is_active": True}, {"_id": 0}
    ).sort("amount", 1).to_list(100)
    return links


